query:
DELETE h1 FROM head_to_head h1
INNER JOIN head_to_head h2
WHERE h1.playerAId = h2.playerAId AND h1.playerBId = h2.playerBId AND h1.id > h2.id;

ALTER TABLE `head_to_head` ADD CONSTRAINT `h2h_pair_idx` UNIQUE(`playerAId`,`playerBId`);

